<?php
namespace App\Http\Controllers;
use App\Models\PrintOrder; use App\Services\Esp32DeviceService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Inertia\Inertia; use Inertia\Response;
class AdminController extends Controller { public function index():Response{return Inertia::render('admin/index',['simulation'=>config('queueless.hardware_simulation'),'orders'=>PrintOrder::with(['locker','deviceCommands'=>fn($q)=>$q->latest()])->latest()->get()->map(fn($o)=>['reference'=>$o->public_reference,'status'=>$o->status->value,'locker'=>$o->locker->locker_number,'pickup_at'=>$o->requested_pickup_at->toIso8601String(),'expires_at'=>$o->expires_at->toIso8601String(),'latest_command'=>$o->deviceCommands->first()?->only(['target_servo','command_type','status','response_payload'])])]);} public function command(Request $r,Esp32DeviceService $device):RedirectResponse{$data=$r->validate(['servo'=>['required','in:catcher,pickup,trash'],'action'=>['required','in:open,close']]);$device->command($data['servo'],$data['action']);return back()->with('success','Device command completed.');} }
